-- ----------------------------
-- Table structure for applications
-- ----------------------------
DROP TABLE IF EXISTS `applications`;
CREATE TABLE `applications`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `job_id` int(11) NOT NULL COMMENT '岗位表主键',
  `candidate_id` int(11) NOT NULL COMMENT '候选人主键',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT '状态(待处理/面试邀约/线下面试/成功入职/已拒绝)',
  `match_score` float NULL DEFAULT 0 COMMENT '匹配度分数',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `interview_location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '面试地点',
  `interview_time` datetime NULL DEFAULT NULL COMMENT '面试时间',
  `interviewer_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '面试官信息',
  `interview_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '面试备注',
  `offer_sent` tinyint(1) NULL DEFAULT 0 COMMENT '是否已发送入职通知',
  `offer_accepted` tinyint(1) NULL DEFAULT 0 COMMENT '候选人是否接受入职通知',
  `interview_invited_at` datetime NULL DEFAULT NULL COMMENT '发送面试邀约的时间',
  `interview_confirmed_at` datetime NULL DEFAULT NULL COMMENT '候选人确认面试的时间',
  `interview_completed_at` datetime NULL DEFAULT NULL COMMENT '线下面试完成的时间',
  `offer_sent_at` datetime NULL DEFAULT NULL COMMENT '发送入职通知的时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `job_id`(`job_id`) USING BTREE,
  INDEX `candidate_id`(`candidate_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_match_score`(`match_score`) USING BTREE,
  CONSTRAINT `applications_ibfk_1` FOREIGN KEY (`job_id`) REFERENCES `jobs` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `applications_ibfk_2` FOREIGN KEY (`candidate_id`) REFERENCES `candidates` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 42 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '申请表' ROW_FORMAT = Dynamic;

